// evidence-seeder.ts -- Populates the evidence_claims table with scientific
// evidence backing food health claims.
//
// Two sources of evidence claims:
// 1. Canonical foods: hardcoded claims from food-database-v1.md
// 2. Remaining foods: to be generated by LLM in a future step
//
// Uses a duplicate check on (food_id, claim) to prevent exact duplicates.
// Claims are append-only -- existing claims are not updated.

import { and, eq } from 'drizzle-orm';
import type { DbClient } from '../client.js';
import { evidenceClaims } from '../schema/index.js';
import type { NewEvidenceClaim } from '../types.js';

// -------------------------------------------------------------------------
// Evidence levels
// -------------------------------------------------------------------------

export const EVIDENCE_LEVELS = ['strong', 'moderate', 'emerging', 'traditional_only'] as const;

export type EvidenceLevel = (typeof EVIDENCE_LEVELS)[number];

// -------------------------------------------------------------------------
// Evidence claim data
// -------------------------------------------------------------------------

export interface EvidenceClaimEntry {
  food_name: string;
  claims: Array<{
    claim: string;
    evidence_level: EvidenceLevel;
    source_citation: string;
    pubmed_id?: string;
  }>;
}

