// -------------------------------------------------------------------------
// Seeder function
// -------------------------------------------------------------------------

/**
 * Seeds the evidence_claims table with curated scientific evidence.
 * Claims are append-only with duplicate checking on (food_id, claim).
 *
 * @param db - Database client (service role).
 * @param foodIdLookup - Map of lowercase food name to food UUID.
 * @returns Total number of evidence claim rows inserted.
 */
export async function seedEvidenceClaims(
  db: DbClient,
  foodIdLookup: Map<string, string>,
): Promise<number> {
  let insertedCount = 0;

  for (const entry of CANONICAL_EVIDENCE_CLAIMS) {
    const foodId = foodIdLookup.get(entry.food_name.toLowerCase());
    if (!foodId) continue;

    for (const claim of entry.claims) {
      // Check for exact duplicate before inserting (append-only pattern)
      const existing = await db
        .select({ id: evidenceClaims.id })
        .from(evidenceClaims)
        .where(and(eq(evidenceClaims.food_id, foodId), eq(evidenceClaims.claim, claim.claim)))
        .limit(1);

      if (existing.length > 0) continue;

      const row: NewEvidenceClaim = {
        food_id: foodId,
        claim: claim.claim,
        evidence_level: claim.evidence_level,
        source_citation: claim.source_citation,
        pubmed_id: claim.pubmed_id ?? null,
      };

      await db.insert(evidenceClaims).values(row);
      insertedCount++;
    }
  }

  return insertedCount;
}
